    pub fn parse_transaction(&self, mut transaction: Value, optional_args: &[Value]) -> Value {
        let mut currency = get_arg(optional_args, 0, Value::Null);
        //
        // withdraw
        //
        //     {
        //         "success": true,
        //         "symbol": "BTC",
        //         "amount": "1.5"
        //     }
        //
        // fetchWithdrawals
        //
        //     {
        //         "timestamp": 1542967486256,
        //         "symbol": "BTC",
        //         "amount": "0.99994",
        //         "address": "BitcoinAddress",
        //         "paymentId": "10002653",
        //         "txId": "927b3ea50c5bb52c6854152d305dfa1e27fc01d10464cf10825d96d69d235eb3",
        //         "fee": "0.00006",
        //         "status": "awaiting_processing"
        //     }
        //
        // fetchDeposits
        //
        //     {
        //         "timestamp":1590492401000,
        //         "symbol":"ETH",
        //         "amount":"0.249825",
        //         "fee":"0",
        //         "status":"completed",
        //         "txId":"0x5167b473fd37811f9ef22364c3d54726a859ef9d98934b3a1e11d7baa8d2c2e2"
        //     }
        //
        let mut id: Value = Value::Null;
        let mut timestamp: Value = self.safe_integer_k(transaction.clone(), "timestamp", &[]);
        let mut currencyId: Value = self.safe_string_k(transaction.clone(), "symbol", &[]);
        let mut code: Value = self.safe_currency_code(currencyId.clone(), &[currency.clone()]);
        let mut status: Value = self.parse_transaction_status(self.safe_string_k(transaction.clone(), "status", &[]));
        let mut amount: Value = self.safe_number_k(transaction.clone(), "amount", &[]);
        let mut address: Value = self.safe_string_k(transaction.clone(), "address", &[]);
        let mut txid: Value = self.safe_string_k(transaction.clone(), "txId", &[]);
        let mut fee: Value = Value::Null;
        let mut feeCost: Value = self.safe_number_k(transaction.clone(), "fee", &[]);
        if !is_equal(&feeCost, &Value::Null) {
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("cost".to_string(), feeCost.clone());
                    m.insert("currency".to_string(), code.clone());
                m
            });
        }
        let mut type_var: Value = Value::Null;
        if is_true(&(Value::Bool(in_op(&transaction, &Value::Str("success".to_string()))))) || is_true(&(Value::Bool(in_op(&transaction, &Value::Str("address".to_string()))))) {
            type_var = Value::Str("withdrawal".to_string());
        }  else {
            type_var = Value::Str("deposit".to_string());
        }
        let mut tag: Value = self.safe_string_k(transaction.clone(), "paymentId", &[]);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), transaction.clone());
        m.insert("id".to_string(), id.clone());
        m.insert("txid".to_string(), txid.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("addressFrom".to_string(), Value::Null);
        m.insert("address".to_string(), address.clone());
        m.insert("addressTo".to_string(), address.clone());
        m.insert("tagFrom".to_string(), Value::Null);
        m.insert("tag".to_string(), tag.clone());
        m.insert("tagTo".to_string(), tag.clone());
        m.insert("type".to_string(), type_var.clone());
        m.insert("amount".to_string(), amount.clone());
        m.insert("currency".to_string(), code.clone());
        m.insert("status".to_string(), status.clone());
        m.insert("updated".to_string(), Value::Null);
        m.insert("fee".to_string(), fee.clone());
        m.insert("network".to_string(), Value::Null);
        m.insert("comment".to_string(), Value::Null);
        m.insert("internal".to_string(), Value::Null);
    m
});

    Value::Null
}

